'use client'
import { useEffect, useState } from 'react'
import { createClient } from '@/lib/supabase'

type AppUser = { id: string; email: string; full_name: string | null; role: string; is_active: boolean }

export function useCurrentUser(schema = 'public', usersTable = 'users') {
  const [user, setUser] = useState<AppUser | null>(null)
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    const supabase = createClient(schema)
    supabase.auth.getUser().then(async ({ data: { user: authUser } }) => {
      if (!authUser) { setLoading(false); return }
      const { data } = await supabase
        .from(usersTable)
        .select('id, email, full_name, role, is_active')
        .eq('auth_user_id', authUser.id)
        .single()
      setUser(data as AppUser | null)
      setLoading(false)
    })
  }, [schema, usersTable])

  return { user, loading, isAdmin: user?.role === 'admin' }
}
